import { Question } from "@/lib/types";

export const questions: Question[] = [
    { id: "y1k1-001", topicRef: "y1k1", topicTitle: "Kinematics 01", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["displacement", "distance", "definitions"], questionText: "A runner completes one full lap of a circular track of circumference \\(400\\) m, returning to the starting point. State the total distance travelled and the total displacement.", workedSolution: { steps: [{ stepNumber: 1, description: "Recall the definitions: distance is the total length of path travelled; displacement is the straight-line distance from start to finish, with direction.", workingLatex: "\\text{Distance} = 400 \\text{ m}", explanation: "The runner covers the full circumference." }, { stepNumber: 2, description: "Since the runner returns to the starting point, the displacement is zero.", workingLatex: "\\text{Displacement} = 0 \\text{ m}", explanation: "Start and finish are the same point, so the net change in position is zero." }], finalAnswer: "Distance \\(= 400\\) m, displacement \\(= 0\\) m." } },
    { id: "y1k1-002", topicRef: "y1k1", topicTitle: "Kinematics 02", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["velocity", "speed", "definitions"], questionText: "A car travels \\(120\\) m due east in \\(8\\) s, then \\(50\\) m due north in \\(4\\) s. Find (a) the average speed and (b) the magnitude of the average velocity for the whole journey.", workedSolution: { steps: [{ stepNumber: 1, description: "Calculate average speed using total distance over total time.", workingLatex: "\\text{Average speed} = \\frac{120 + 50}{8 + 4} = \\frac{170}{12} \\approx 14.2 \\text{ m/s}", explanation: "Speed uses the total path length regardless of direction." }, { stepNumber: 2, description: "Find the resultant displacement using Pythagoras.", workingLatex: "\\text{Displacement} = \\sqrt{120^2 + 50^2} = \\sqrt{14400 + 2500} = \\sqrt{16900} = 130 \\text{ m}", explanation: "The east and north components are perpendicular." }, { stepNumber: 3, description: "Calculate the magnitude of the average velocity.", workingLatex: "\\text{Average velocity} = \\frac{130}{12} \\approx 10.8 \\text{ m/s}", explanation: "Velocity uses displacement divided by total time." }], finalAnswer: "(a) Average speed \\(\\approx 14.2\\) m/s. (b) Magnitude of average velocity \\(\\approx 10.8\\) m/s." } },
    { id: "y1k1-003", topicRef: "y1k1", topicTitle: "Kinematics 03", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["direction", "sign convention", "displacement"], questionText: "A particle moves \\(7\\) m to the right, then \\(3\\) m to the left along a straight line. Taking rightward as positive, state (a) the total distance travelled and (b) the displacement from the starting point.", workedSolution: { steps: [{ stepNumber: 1, description: "Calculate the total distance.", workingLatex: "\\text{Distance} = 7 + 3 = 10 \\text{ m}", explanation: "Distance is always positive and adds all lengths." }, { stepNumber: 2, description: "Calculate the displacement using the sign convention.", workingLatex: "\\text{Displacement} = (+7) + (-3) = +4 \\text{ m}", explanation: "Rightward is positive and leftward is negative, so the net displacement is 4 m to the right." }], finalAnswer: "(a) Distance \\(= 10\\) m. (b) Displacement \\(= +4\\) m (i.e. 4 m to the right)." } },
    { id: "y1k1-004", topicRef: "y1k1", topicTitle: "Kinematics 04", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Standard", tags: ["velocity", "speed", "sign convention", "direction"], questionText: "A ball is thrown vertically upward with a speed of \\(12\\) m/s. Taking upward as positive, write down the initial velocity and the acceleration due to gravity acting on the ball. State the velocity of the ball at its highest point.", workedSolution: { steps: [{ stepNumber: 1, description: "Write the initial velocity using the sign convention.", workingLatex: "u = +12 \\text{ m/s}", explanation: "Upward is taken as positive, and the ball is thrown upward." }, { stepNumber: 2, description: "Write the acceleration due to gravity.", workingLatex: "a = -9.8 \\text{ m/s}^2", explanation: "Gravity acts downward, which is negative under our convention." }, { stepNumber: 3, description: "State the velocity at the highest point.", workingLatex: "v = 0 \\text{ m/s}", explanation: "At the highest point the ball momentarily stops before falling back down." }], finalAnswer: "\\(u = +12\\) m/s, \\(a = -9.8\\) m/s\\(^2\\), and \\(v = 0\\) m/s at the highest point." } },
    { id: "y1k1-005", topicRef: "y1k1", topicTitle: "Kinematics 05", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Standard", tags: ["displacement-time graph", "gradient", "velocity"], questionText: "A displacement--time graph for a particle shows the following: from \\(t = 0\\) to \\(t = 4\\) s the displacement increases uniformly from \\(0\\) to \\(20\\) m, and from \\(t = 4\\) to \\(t = 10\\) s the displacement remains at \\(20\\) m. Find the velocity of the particle in each stage.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the velocity from \\(t = 0\\) to \\(t = 4\\) s using the gradient of the displacement--time graph.", workingLatex: "v = \\frac{\\Delta s}{\\Delta t} = \\frac{20 - 0}{4 - 0} = 5 \\text{ m/s}", explanation: "The gradient of a displacement--time graph gives velocity." }, { stepNumber: 2, description: "Find the velocity from \\(t = 4\\) to \\(t = 10\\) s.", workingLatex: "v = \\frac{\\Delta s}{\\Delta t} = \\frac{20 - 20}{10 - 4} = 0 \\text{ m/s}", explanation: "The displacement is constant, so the particle is stationary." }], finalAnswer: "From \\(t = 0\\) to \\(t = 4\\) s: \\(v = 5\\) m/s. From \\(t = 4\\) to \\(t = 10\\) s: \\(v = 0\\) m/s." } },
    { id: "y1k1-006", topicRef: "y1k1", topicTitle: "Kinematics 06", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Standard", tags: ["velocity-time graph", "acceleration", "displacement", "area"], questionText: "A velocity--time graph for a car shows a straight line from \\((0,\\, 0)\\) to \\((5,\\, 15)\\). Find (a) the acceleration and (b) the displacement of the car during this \\(5\\) s interval.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the acceleration from the gradient of the velocity--time graph.", workingLatex: "a = \\frac{\\Delta v}{\\Delta t} = \\frac{15 - 0}{5 - 0} = 3 \\text{ m/s}^2", explanation: "The gradient of a velocity--time graph gives acceleration." }, { stepNumber: 2, description: "Find the displacement from the area under the velocity--time graph. The region is a triangle.", workingLatex: "s = \\tfrac{1}{2} \\times \\text{base} \\times \\text{height} = \\tfrac{1}{2} \\times 5 \\times 15 = 37.5 \\text{ m}", explanation: "The area under a velocity--time graph gives the displacement." }], finalAnswer: "(a) \\(a = 3\\) m/s\\(^2\\). (b) \\(s = 37.5\\) m." } },
    { id: "y1k1-007", topicRef: "y1k1", topicTitle: "Kinematics 07", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["velocity-time graph", "area", "multi-stage", "trapezium"], questionText: "A cyclist accelerates uniformly from rest to \\(8\\) m/s in \\(10\\) s, travels at \\(8\\) m/s for \\(20\\) s, then decelerates uniformly to rest in \\(5\\) s. Calculate the total displacement.", workedSolution: { steps: [{ stepNumber: 1, description: "Calculate the displacement during the acceleration phase (triangle).", workingLatex: "s_1 = \\tfrac{1}{2} \\times 10 \\times 8 = 40 \\text{ m}", explanation: "Area of the triangle under the velocity--time graph from 0 to 10 s." }, { stepNumber: 2, description: "Calculate the displacement during the constant velocity phase (rectangle).", workingLatex: "s_2 = 8 \\times 20 = 160 \\text{ m}", explanation: "Area of the rectangle from 10 s to 30 s." }, { stepNumber: 3, description: "Calculate the displacement during the deceleration phase (triangle).", workingLatex: "s_3 = \\tfrac{1}{2} \\times 5 \\times 8 = 20 \\text{ m}", explanation: "Area of the triangle from 30 s to 35 s." }, { stepNumber: 4, description: "Add all three parts.", workingLatex: "s = 40 + 160 + 20 = 220 \\text{ m}", explanation: "Total displacement is the sum of the three areas." }], finalAnswer: "Total displacement \\(= 220\\) m." } },
    { id: "y1k1-008", topicRef: "y1k1", topicTitle: "Kinematics 08", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["displacement-time graph", "gradient", "negative velocity"], questionText: "A displacement--time graph for a particle is a straight line from \\((0,\\, 12)\\) to \\((6,\\, 0)\\). What is the velocity of the particle? Interpret the sign of your answer.", workedSolution: { steps: [{ stepNumber: 1, description: "Calculate the gradient of the line.", workingLatex: "v = \\frac{0 - 12}{6 - 0} = \\frac{-12}{6} = -2 \\text{ m/s}", explanation: "Velocity is the gradient of the displacement--time graph." }, { stepNumber: 2, description: "Interpret the negative sign.", workingLatex: "v = -2 \\text{ m/s (particle moves in the negative direction)}", explanation: "The negative velocity means the particle is moving back towards (or past) the origin." }], finalAnswer: "\\(v = -2\\) m/s. The particle moves in the negative direction at \\(2\\) m/s." } },
    { id: "y1k1-009", topicRef: "y1k1", topicTitle: "Kinematics 09", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["velocity-time graph", "area", "algebraic proof", "show that", "trapezium"], questionText: "A particle moves along a straight line. Its velocity--time graph consists of three straight-line segments: the velocity increases uniformly from \\(0\\) to \\(V\\) m/s over a time interval of \\(T_1\\) seconds, remains constant at \\(V\\) m/s for \\(T_2\\) seconds, then decreases uniformly from \\(V\\) to \\(0\\) over \\(T_3\\) seconds. (a) Show that the total displacement is \\(\\dfrac{V(T_1 + 2T_2 + T_3)}{2}\\). (b) Given that \\(T_1 = T_3\\), show that the total displacement simplifies to \\(V(T_1 + T_2)\\). (c) Explain geometrically why the result in (b) is equivalent to the area of a rectangle of width \\((T_1 + T_2)\\) and height \\(V\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Find the displacement in the acceleration phase (triangle).", workingLatex: "s_1 = \\tfrac{1}{2} \\times T_1 \\times V = \\frac{VT_1}{2}", explanation: "The area under the velocity--time graph in the first phase is a triangle with base \\(T_1\\) and height \\(V\\)." }, { stepNumber: 2, description: "Find the displacement in the constant velocity phase (rectangle).", workingLatex: "s_2 = V \\times T_2 = VT_2", explanation: "A rectangle of width \\(T_2\\) and height \\(V\\)." }, { stepNumber: 3, description: "Find the displacement in the deceleration phase (triangle).", workingLatex: "s_3 = \\tfrac{1}{2} \\times T_3 \\times V = \\frac{VT_3}{2}", explanation: "Another triangle with base \\(T_3\\) and height \\(V\\)." }, { stepNumber: 4, description: "Sum to find the total displacement.", workingLatex: "s = \\frac{VT_1}{2} + VT_2 + \\frac{VT_3}{2} = \\frac{VT_1 + 2VT_2 + VT_3}{2} = \\frac{V(T_1 + 2T_2 + T_3)}{2}", explanation: "As required for part (a)." }, { stepNumber: 5, description: "Substitute \\(T_1 = T_3\\) for part (b).", workingLatex: "s = \\frac{V(T_1 + 2T_2 + T_1)}{2} = \\frac{V(2T_1 + 2T_2)}{2} = V(T_1 + T_2)", explanation: "As required for part (b)." }, { stepNumber: 6, description: "Geometric explanation for part (c).", workingLatex: "\\text{When } T_1 = T_3, \\text{ the trapezium is symmetric: the triangle 'missing' from the top-right can fill the top-left, forming a rectangle of width } (T_1 + T_2) \\text{ and height } V.", explanation: "The two equal triangles at each end combine with the central rectangle to form a shape whose area equals that of a rectangle with base \\((T_1 + T_2)\\) and height \\(V\\). This is because the average of the parallel sides of the symmetric trapezium is \\(V\\), and the effective width is \\((T_1 + T_2)\\)." }], finalAnswer: "(a) Total displacement \\(= \\dfrac{V(T_1 + 2T_2 + T_3)}{2}\\) as required. (b) When \\(T_1 = T_3\\), this simplifies to \\(V(T_1 + T_2)\\) as required. (c) The symmetric trapezium can be rearranged into a rectangle of width \\((T_1 + T_2)\\) and height \\(V\\)." } },
    { id: "y1k1-010", topicRef: "y1k1", topicTitle: "Kinematics 10", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["suvat", "simultaneous equations", "algebraic", "multi-stage"], questionText: "A car starts from rest and accelerates uniformly at \\(a\\) m/s\\(^2\\) for \\(T\\) seconds, reaching a final speed of \\(V\\) m/s. During this time it covers a total distance of \\(D\\) metres. (a) By forming two equations in \\(a\\) and \\(T\\), show that \\(T = \\dfrac{2D}{V}\\) and \\(a = \\dfrac{V^2}{2D}\\). (b) Given that \\(V = 30\\) and \\(D = 225\\), find the values of \\(a\\) and \\(T\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Use \\(v = u + at\\) with \\(u = 0\\) to form equation (1).", workingLatex: "V = aT \\quad \\cdots (1)", explanation: "The car starts from rest and reaches speed \\(V\\) after time \\(T\\)." }, { stepNumber: 2, description: "Use \\(s = ut + \\tfrac{1}{2}at^2\\) with \\(u = 0\\) to form equation (2).", workingLatex: "D = \\tfrac{1}{2}aT^2 \\quad \\cdots (2)", explanation: "Total distance covered is \\(D\\)." }, { stepNumber: 3, description: "From (1), \\(a = V/T\\). Substitute into (2).", workingLatex: "D = \\tfrac{1}{2} \\cdot \\frac{V}{T} \\cdot T^2 = \\frac{VT}{2}", explanation: "" }, { stepNumber: 4, description: "Solve for \\(T\\).", workingLatex: "T = \\frac{2D}{V} \\quad \\text{as required.}", explanation: "" }, { stepNumber: 5, description: "Substitute back to find \\(a\\).", workingLatex: "a = \\frac{V}{T} = \\frac{V}{2D/V} = \\frac{V^2}{2D} \\quad \\text{as required.}", explanation: "" }, { stepNumber: 6, description: "Substitute \\(V = 30\\) and \\(D = 225\\) for part (b).", workingLatex: "T = \\frac{2 \\times 225}{30} = 15 \\text{ s}, \\quad a = \\frac{30^2}{2 \\times 225} = \\frac{900}{450} = 2 \\text{ m/s}^2", explanation: "" }], finalAnswer: "(a) \\(T = \\dfrac{2D}{V}\\) and \\(a = \\dfrac{V^2}{2D}\\) as required. (b) \\(T = 15\\) s, \\(a = 2\\) m/s\\(^2\\)." } },
    { id: "y1k1-011", topicRef: "y1k1", topicTitle: "Kinematics 11", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["suvat", "v = u + at", "constant acceleration"], questionText: "A car accelerates uniformly from \\(10\\) m/s at \\(2\\) m/s\\(^2\\) for \\(6\\) s. Find the final velocity.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the known values.", workingLatex: "u = 10, \\quad a = 2, \\quad t = 6", explanation: "We know \\(u\\), \\(a\\) and \\(t\\); we want \\(v\\)." }, { stepNumber: 2, description: "Apply \\(v = u + at\\).", workingLatex: "v = 10 + 2 \\times 6 = 10 + 12 = 22 \\text{ m/s}", explanation: "Substitute the values directly." }], finalAnswer: "\\(v = 22\\) m/s." } },
    { id: "y1k1-012", topicRef: "y1k1", topicTitle: "Kinematics 12", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["suvat", "s = ut + half at squared", "constant acceleration"], questionText: "A particle starts from rest and accelerates uniformly at \\(3\\) m/s\\(^2\\). Find the displacement after \\(4\\) s.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the known values.", workingLatex: "u = 0, \\quad a = 3, \\quad t = 4", explanation: "Starts from rest means \\(u = 0\\)." }, { stepNumber: 2, description: "Apply \\(s = ut + \\tfrac{1}{2}at^2\\).", workingLatex: "s = 0 \\times 4 + \\tfrac{1}{2} \\times 3 \\times 4^2 = 0 + \\tfrac{1}{2} \\times 3 \\times 16 = 24 \\text{ m}", explanation: "Since \\(u = 0\\), the first term vanishes." }], finalAnswer: "\\(s = 24\\) m." } },
    { id: "y1k1-013", topicRef: "y1k1", topicTitle: "Kinematics 13", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Standard", tags: ["suvat", "v squared = u squared + 2as", "braking"], questionText: "A car is travelling at \\(20\\) m/s when the brakes are applied, producing a deceleration of \\(4\\) m/s\\(^2\\). Find the distance the car travels before coming to rest.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the known values.", workingLatex: "u = 20, \\quad v = 0, \\quad a = -4", explanation: "The car decelerates, so \\(a\\) is negative. It comes to rest so \\(v = 0\\)." }, { stepNumber: 2, description: "Apply \\(v^2 = u^2 + 2as\\) and solve for \\(s\\).", workingLatex: "0 = 20^2 + 2(-4)s \\implies 0 = 400 - 8s \\implies s = \\frac{400}{8} = 50 \\text{ m}", explanation: "Rearrange to find the braking distance." }], finalAnswer: "\\(s = 50\\) m." } },
    { id: "y1k1-014", topicRef: "y1k1", topicTitle: "Kinematics 14", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Standard", tags: ["suvat", "s = half(u + v)t", "constant acceleration"], questionText: "A train decelerates uniformly from \\(30\\) m/s to \\(10\\) m/s over a distance of \\(200\\) m. Find the time taken.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the known values.", workingLatex: "u = 30, \\quad v = 10, \\quad s = 200", explanation: "We know \\(u\\), \\(v\\) and \\(s\\); we want \\(t\\)." }, { stepNumber: 2, description: "Apply \\(s = \\tfrac{1}{2}(u + v)t\\) and solve for \\(t\\).", workingLatex: "200 = \\tfrac{1}{2}(30 + 10)\\,t = \\tfrac{1}{2} \\times 40 \\times t = 20t", explanation: "This SUVAT equation does not require acceleration." }, { stepNumber: 3, description: "Solve for \\(t\\).", workingLatex: "t = \\frac{200}{20} = 10 \\text{ s}", explanation: "" }], finalAnswer: "\\(t = 10\\) s." } },
    { id: "y1k1-015", topicRef: "y1k1", topicTitle: "Kinematics 15", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["suvat", "vertical motion", "gravity", "v = u + at"], questionText: "A ball is thrown vertically upward from ground level with a speed of \\(19.6\\) m/s. Taking \\(g = 9.8\\) m/s\\(^2\\) and upward as positive, find (a) the time taken to reach the highest point and (b) the maximum height.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the known values.", workingLatex: "u = 19.6, \\quad v = 0, \\quad a = -9.8", explanation: "At the highest point \\(v = 0\\). Upward is positive so \\(a = -g = -9.8\\)." }, { stepNumber: 2, description: "Apply \\(v = u + at\\) to find the time.", workingLatex: "0 = 19.6 + (-9.8)t \\implies 9.8t = 19.6 \\implies t = 2 \\text{ s}", explanation: "" }, { stepNumber: 3, description: "Apply \\(s = ut + \\tfrac{1}{2}at^2\\) to find the maximum height.", workingLatex: "s = 19.6 \\times 2 + \\tfrac{1}{2}(-9.8)(2)^2 = 39.2 - 19.6 = 19.6 \\text{ m}", explanation: "Alternatively, use \\(v^2 = u^2 + 2as\\): \\(0 = 19.6^2 + 2(-9.8)s \\Rightarrow s = 19.6\\) m." }], finalAnswer: "(a) \\(t = 2\\) s. (b) Maximum height \\(= 19.6\\) m." } },
    { id: "y1k1-016", topicRef: "y1k1", topicTitle: "Kinematics 16", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["suvat", "vertical motion", "gravity", "time of flight"], questionText: "A stone is dropped from rest from the top of a cliff \\(44.1\\) m above the sea. Taking \\(g = 9.8\\) m/s\\(^2\\), find (a) the time for the stone to reach the sea and (b) the speed at which it hits the sea.", workedSolution: { steps: [{ stepNumber: 1, description: "Set up with downward as positive.", workingLatex: "u = 0, \\quad s = 44.1, \\quad a = 9.8", explanation: "Dropped from rest so \\(u = 0\\). Taking downward as positive." }, { stepNumber: 2, description: "Apply \\(s = ut + \\tfrac{1}{2}at^2\\) to find \\(t\\).", workingLatex: "44.1 = 0 + \\tfrac{1}{2}(9.8)t^2 = 4.9t^2 \\implies t^2 = \\frac{44.1}{4.9} = 9 \\implies t = 3 \\text{ s}", explanation: "Take the positive root." }, { stepNumber: 3, description: "Apply \\(v = u + at\\) to find the speed.", workingLatex: "v = 0 + 9.8 \\times 3 = 29.4 \\text{ m/s}", explanation: "" }], finalAnswer: "(a) \\(t = 3\\) s. (b) \\(v = 29.4\\) m/s." } },
    { id: "y1k1-017", topicRef: "y1k1", topicTitle: "Kinematics 17", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["suvat", "two-stage", "algebraic proof", "show that"], questionText: "A particle starts from rest and accelerates uniformly at \\(a\\) m/s\\(^2\\) for \\(t_1\\) seconds, reaching speed \\(V\\) m/s. It then decelerates uniformly at \\(2a\\) m/s\\(^2\\) until it comes to rest. (a) Show that \\(t_1 = \\dfrac{V}{a}\\). (b) Find the time for the deceleration phase in terms of \\(V\\) and \\(a\\). (c) Show that the total distance travelled is \\(\\dfrac{3V^2}{4a}\\). (d) Hence find the total distance when \\(V = 12\\) and \\(a = 3\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Use \\(v = u + at\\) for the acceleration phase.", workingLatex: "V = 0 + a \\cdot t_1 \\implies t_1 = \\frac{V}{a} \\quad \\text{as required for (a).}", explanation: "The particle starts from rest so \\(u = 0\\)." }, { stepNumber: 2, description: "Find the deceleration time for part (b). The particle decelerates from \\(V\\) to \\(0\\) at rate \\(2a\\).", workingLatex: "0 = V - 2a \\cdot t_2 \\implies t_2 = \\frac{V}{2a}", explanation: "" }, { stepNumber: 3, description: "Find the distance in the acceleration phase.", workingLatex: "s_1 = \\tfrac{1}{2} a t_1^2 = \\tfrac{1}{2} a \\left(\\frac{V}{a}\\right)^2 = \\frac{V^2}{2a}", explanation: "" }, { stepNumber: 4, description: "Find the distance in the deceleration phase using \\(v^2 = u^2 + 2as\\).", workingLatex: "0 = V^2 + 2(-2a)s_2 \\implies 4a \\cdot s_2 = V^2 \\implies s_2 = \\frac{V^2}{4a}", explanation: "" }, { stepNumber: 5, description: "Sum to find the total distance for part (c).", workingLatex: "s = s_1 + s_2 = \\frac{V^2}{2a} + \\frac{V^2}{4a} = \\frac{2V^2 + V^2}{4a} = \\frac{3V^2}{4a} \\quad \\text{as required.}", explanation: "" }, { stepNumber: 6, description: "Substitute \\(V = 12\\) and \\(a = 3\\) for part (d).", workingLatex: "s = \\frac{3 \\times 12^2}{4 \\times 3} = \\frac{3 \\times 144}{12} = \\frac{432}{12} = 36 \\text{ m}", explanation: "" }], finalAnswer: "(a) \\(t_1 = \\dfrac{V}{a}\\) as required. (b) \\(t_2 = \\dfrac{V}{2a}\\). (c) Total distance \\(= \\dfrac{3V^2}{4a}\\) as required. (d) \\(s = 36\\) m." } },
    { id: "y1k1-018", topicRef: "y1k1", topicTitle: "Kinematics 18", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["suvat", "two particles", "algebraic", "simultaneous equations", "relative motion"], questionText: "Two particles \\(P\\) and \\(Q\\) are initially at points \\(A\\) and \\(B\\) respectively, where \\(AB = d\\) metres. At time \\(t = 0\\), particle \\(P\\) is projected from \\(A\\) toward \\(B\\) with speed \\(u_1\\) m/s and constant acceleration \\(a\\) m/s\\(^2\\) in the direction \\(AB\\). At the same instant, particle \\(Q\\) is projected from \\(B\\) toward \\(A\\) with speed \\(u_2\\) m/s and the same constant acceleration \\(a\\) m/s\\(^2\\) in the direction \\(BA\\). (a) Show that the particles meet at time \\(t = \\dfrac{d}{u_1 + u_2}\\). (b) Show that the distance from \\(A\\) to the meeting point is \\(\\dfrac{d\\,u_1}{u_1 + u_2} + \\dfrac{a d^2}{2(u_1 + u_2)^2}\\). (c) State the condition on \\(u_1\\), \\(u_2\\) and \\(a\\) for the meeting point to be exactly at the midpoint of \\(AB\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Set up a coordinate axis from \\(A\\) to \\(B\\). Write the position of \\(P\\) at time \\(t\\).", workingLatex: "x_P = u_1 t + \\tfrac{1}{2} a t^2", explanation: "\\(P\\) starts at \\(A\\) (position 0) moving in the positive direction with acceleration \\(a\\)." }, { stepNumber: 2, description: "Write the position of \\(Q\\) at time \\(t\\). \\(Q\\) starts at \\(B\\) (position \\(d\\)), moves toward \\(A\\) with speed \\(u_2\\) and acceleration \\(a\\) toward \\(A\\). In our coordinate system, \\(Q\\)'s velocity is \\(-u_2\\) and acceleration is \\(-a\\).", workingLatex: "x_Q = d - u_2 t - \\tfrac{1}{2} a t^2", explanation: "Both the velocity and acceleration of \\(Q\\) are in the negative direction." }, { stepNumber: 3, description: "Set \\(x_P = x_Q\\) for the meeting condition.", workingLatex: "u_1 t + \\tfrac{1}{2} a t^2 = d - u_2 t - \\tfrac{1}{2} a t^2", explanation: "" }, { stepNumber: 4, description: "Collect terms. The \\(\\tfrac{1}{2}at^2\\) terms cancel.", workingLatex: "u_1 t + u_2 t = d \\implies (u_1 + u_2)t = d \\implies t = \\frac{d}{u_1 + u_2} \\quad \\text{as required for (a).}", explanation: "The acceleration terms cancel because both particles accelerate toward each other with equal magnitude." }, { stepNumber: 5, description: "Part (b): Find the distance from \\(A\\) by substituting \\(t = d/(u_1 + u_2)\\) into \\(x_P\\).", workingLatex: "x_P = u_1 \\cdot \\frac{d}{u_1 + u_2} + \\tfrac{1}{2} a \\left(\\frac{d}{u_1 + u_2}\\right)^2 = \\frac{d u_1}{u_1 + u_2} + \\frac{a d^2}{2(u_1 + u_2)^2} \\quad \\text{as required.}", explanation: "" }, { stepNumber: 6, description: "Part (c): Set \\(x_P = d/2\\) and simplify. Divide through by \\(d\\).", workingLatex: "\\frac{u_1}{u_1 + u_2} + \\frac{ad}{2(u_1+u_2)^2} = \\frac{1}{2}", explanation: "" }, { stepNumber: 7, description: "Multiply through by \\(2(u_1+u_2)^2\\).", workingLatex: "2u_1(u_1+u_2) + ad = (u_1+u_2)^2", explanation: "" }, { stepNumber: 8, description: "Expand and simplify.", workingLatex: "2u_1^2 + 2u_1 u_2 + ad = u_1^2 + 2u_1 u_2 + u_2^2 \\implies u_1^2 + ad = u_2^2 \\implies ad = u_2^2 - u_1^2", explanation: "So they meet at the midpoint when \\(ad = u_2^2 - u_1^2\\). In particular, if \\(a = 0\\) then they meet at the midpoint only when \\(u_1 = u_2\\)." }], finalAnswer: "(a) \\(t = \\dfrac{d}{u_1 + u_2}\\) as required. (b) Distance from \\(A\\) is \\(\\dfrac{du_1}{u_1+u_2} + \\dfrac{ad^2}{2(u_1+u_2)^2}\\) as required. (c) They meet at the midpoint when \\(ad = u_2^2 - u_1^2\\)." } },
    { id: "y1k1-019", topicRef: "y1k1", topicTitle: "Kinematics 19", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["suvat", "vertical motion", "algebraic proof", "show that", "energy"], questionText: "A ball is projected vertically upward with speed \\(U\\) m/s from a point \\(h\\) metres above the ground. (a) Show that the speed of the ball when it hits the ground is \\(\\sqrt{U^2 + 2gh}\\), regardless of whether the ball is projected upward or downward. (b) Explain in one sentence why the direction of projection does not affect the final speed. (c) Given \\(U = 10\\) and \\(h = 15\\), find the speed at which the ball hits the ground. Take \\(g = 9.8\\) m/s\\(^2\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Take upward as positive with origin at the launch point. The ground is at displacement \\(s = -h\\).", workingLatex: "u = +U, \\quad a = -g, \\quad s = -h", explanation: "The ball is projected upward so \\(u > 0\\), gravity acts downward, and the ground is below the launch point." }, { stepNumber: 2, description: "Apply \\(v^2 = u^2 + 2as\\).", workingLatex: "v^2 = U^2 + 2(-g)(-h) = U^2 + 2gh", explanation: "" }, { stepNumber: 3, description: "Take the positive square root (speed is the magnitude of velocity).", workingLatex: "\\text{Speed} = |v| = \\sqrt{U^2 + 2gh} \\quad \\text{as required.}", explanation: "Note that if the ball were projected downward instead, we would have \\(u = -U\\), and \\(v^2 = (-U)^2 + 2(-g)(-h) = U^2 + 2gh\\), giving the same result." }, { stepNumber: 4, description: "Part (b): Explanation.", workingLatex: "\\text{The SUVAT equation } v^2 = u^2 + 2as \\text{ depends on } u^2, \\text{ so the sign (direction) of } u \\text{ does not matter.}", explanation: "Whether projected up or down, the initial kinetic energy contribution is \\(U^2\\), and the gravitational contribution is \\(2gh\\), so the final speed is the same." }, { stepNumber: 5, description: "Part (c): Substitute the numerical values.", workingLatex: "\\text{Speed} = \\sqrt{10^2 + 2(9.8)(15)} = \\sqrt{100 + 294} = \\sqrt{394} \\approx 19.8 \\text{ m/s}", explanation: "" }], finalAnswer: "(a) Speed \\(= \\sqrt{U^2 + 2gh}\\) as required. (b) The equation \\(v^2 = u^2 + 2as\\) involves \\(u^2\\), so the sign of the initial velocity is irrelevant. (c) Speed \\(\\approx 19.8\\) m/s." } },
    { id: "y1k1-020", topicRef: "y1k1", topicTitle: "Kinematics 20", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["suvat", "nth second", "simultaneous equations", "constant acceleration"], questionText: "A particle \\(P\\) travels along a straight line with constant acceleration. In the 3rd second of its motion it travels \\(5\\) m, and in the 7th second it travels \\(13\\) m. (a) Using the formula for the distance covered in the \\(n\\)th second, \\(s_n = u + \\tfrac{1}{2}a(2n - 1)\\), form two simultaneous equations. (b) Find the initial speed \\(u\\) and the acceleration \\(a\\). (c) Find the total distance travelled in the first \\(10\\) seconds.", workedSolution: { steps: [{ stepNumber: 1, description: "Apply the nth-second formula for \\(n = 3\\).", workingLatex: "s_3 = u + \\tfrac{1}{2}a(2 \\times 3 - 1) = u + \\tfrac{5a}{2} = 5 \\quad \\cdots (1)", explanation: "The distance in the 3rd second is 5 m." }, { stepNumber: 2, description: "Apply the nth-second formula for \\(n = 7\\).", workingLatex: "s_7 = u + \\tfrac{1}{2}a(2 \\times 7 - 1) = u + \\tfrac{13a}{2} = 13 \\quad \\cdots (2)", explanation: "The distance in the 7th second is 13 m." }, { stepNumber: 3, description: "Subtract equation (1) from equation (2).", workingLatex: "\\left(u + \\tfrac{13a}{2}\\right) - \\left(u + \\tfrac{5a}{2}\\right) = 13 - 5 \\implies \\tfrac{8a}{2} = 8 \\implies 4a = 8 \\implies a = 2 \\text{ m/s}^2", explanation: "" }, { stepNumber: 4, description: "Substitute \\(a = 2\\) into equation (1) to find \\(u\\).", workingLatex: "u + \\tfrac{5 \\times 2}{2} = 5 \\implies u + 5 = 5 \\implies u = 0 \\text{ m/s}", explanation: "The particle starts from rest." }, { stepNumber: 5, description: "Find the total distance in the first 10 seconds using \\(s = ut + \\tfrac{1}{2}at^2\\).", workingLatex: "s = 0 \\times 10 + \\tfrac{1}{2}(2)(10)^2 = 100 \\text{ m}", explanation: "" }], finalAnswer: "(a) Equations: \\(u + \\tfrac{5a}{2} = 5\\) and \\(u + \\tfrac{13a}{2} = 13\\). (b) \\(u = 0\\) m/s, \\(a = 2\\) m/s\\(^2\\). (c) Total distance \\(= 100\\) m." } },
    { id: "y1k1-021", topicRef: "y1k1", topicTitle: "Kinematics 21", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Foundation", tags: ["suvat", "two-stage", "accelerate then decelerate"], questionText: "A cyclist accelerates uniformly from rest at \\(1.5\\) m/s\\(^2\\) for \\(10\\) s, then decelerates uniformly at \\(0.5\\) m/s\\(^2\\) until coming to rest. Find (a) the maximum speed and (b) the total distance travelled.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the maximum speed at the end of the acceleration phase.", workingLatex: "v = u + at = 0 + 1.5 \\times 10 = 15 \\text{ m/s}", explanation: "The cyclist starts from rest and accelerates for 10 s." }, { stepNumber: 2, description: "Find the distance during the acceleration phase.", workingLatex: "s_1 = ut + \\tfrac{1}{2}at^2 = 0 + \\tfrac{1}{2}(1.5)(10)^2 = 75 \\text{ m}", explanation: "" }, { stepNumber: 3, description: "Find the distance during the deceleration phase using \\(v^2 = u^2 + 2as\\).", workingLatex: "0 = 15^2 + 2(-0.5)s_2 \\implies s_2 = \\frac{225}{1} = 225 \\text{ m}", explanation: "The cyclist decelerates from 15 m/s to rest." }, { stepNumber: 4, description: "Find the total distance.", workingLatex: "s = s_1 + s_2 = 75 + 225 = 300 \\text{ m}", explanation: "" }], finalAnswer: "(a) Maximum speed \\(= 15\\) m/s. (b) Total distance \\(= 300\\) m." } },
    { id: "y1k1-022", topicRef: "y1k1", topicTitle: "Kinematics 22", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Foundation", tags: ["suvat", "vertical motion", "max height", "time to return"], questionText: "A ball is thrown vertically upward from ground level at \\(29.4\\) m/s. Taking \\(g = 9.8\\) m/s\\(^2\\), find (a) the maximum height reached and (b) the total time for the ball to return to ground level.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the maximum height. Take upward as positive.", workingLatex: "v^2 = u^2 + 2as: \\quad 0 = 29.4^2 + 2(-9.8)s \\implies s = \\frac{864.36}{19.6} = 44.1 \\text{ m}", explanation: "At maximum height, \\(v = 0\\)." }, { stepNumber: 2, description: "Find the time to reach the highest point.", workingLatex: "v = u + at: \\quad 0 = 29.4 - 9.8t \\implies t = 3 \\text{ s}", explanation: "" }, { stepNumber: 3, description: "By symmetry, the total time to return to the ground is twice the time to the highest point.", workingLatex: "T = 2 \\times 3 = 6 \\text{ s}", explanation: "The ball takes the same time going up as coming down (no air resistance)." }], finalAnswer: "(a) Maximum height \\(= 44.1\\) m. (b) Total time \\(= 6\\) s." } },
    { id: "y1k1-023", topicRef: "y1k1", topicTitle: "Kinematics 23", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Foundation", tags: ["suvat", "two-stage", "constant velocity then braking"], questionText: "A car travels at a constant speed of \\(25\\) m/s for \\(12\\) s, then brakes with a uniform deceleration of \\(5\\) m/s\\(^2\\) until it comes to rest. Find (a) the braking time and (b) the total distance covered.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the distance during the constant speed phase.", workingLatex: "s_1 = 25 \\times 12 = 300 \\text{ m}", explanation: "" }, { stepNumber: 2, description: "Find the braking time using \\(v = u + at\\).", workingLatex: "0 = 25 + (-5)t \\implies t = 5 \\text{ s}", explanation: "" }, { stepNumber: 3, description: "Find the braking distance.", workingLatex: "s_2 = \\tfrac{1}{2}(25 + 0)(5) = 62.5 \\text{ m}", explanation: "Using \\(s = \\tfrac{1}{2}(u + v)t\\)." }, { stepNumber: 4, description: "Add the two distances.", workingLatex: "s = 300 + 62.5 = 362.5 \\text{ m}", explanation: "" }], finalAnswer: "(a) Braking time \\(= 5\\) s. (b) Total distance \\(= 362.5\\) m." } },
    { id: "y1k1-024", topicRef: "y1k1", topicTitle: "Kinematics 24", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Foundation", tags: ["suvat", "vertical motion", "time of flight", "symmetry"], questionText: "A stone is thrown vertically upward from ground level at \\(14.7\\) m/s. Taking \\(g = 9.8\\) m/s\\(^2\\), find the speed of the stone when it is \\(9.8\\) m above the ground.", workedSolution: { steps: [{ stepNumber: 1, description: "Take upward as positive. Use \\(v^2 = u^2 + 2as\\) with \\(s = 9.8\\).", workingLatex: "v^2 = 14.7^2 + 2(-9.8)(9.8) = 216.09 - 192.08 = 24.01", explanation: "" }, { stepNumber: 2, description: "Find the speed.", workingLatex: "v = \\sqrt{24.01} = 4.9 \\text{ m/s}", explanation: "The speed is the same on the way up and on the way down at this height; the velocity is \\(+4.9\\) m/s going up and \\(-4.9\\) m/s coming down." }], finalAnswer: "Speed \\(= 4.9\\) m/s." } },
    { id: "y1k1-025", topicRef: "y1k1", topicTitle: "Kinematics 25", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["suvat", "two-stage", "show that"], questionText: "A particle starts from rest and accelerates uniformly at \\(a\\) m/s\\(^2\\) for \\(T\\) seconds, reaching speed \\(V\\) m/s. It then decelerates uniformly at \\(2a\\) m/s\\(^2\\) until it stops. Show that the total distance travelled is \\(\\dfrac{3V^2}{4a}\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Express \\(V\\) in terms of \\(a\\) and \\(T\\).", workingLatex: "V = 0 + aT = aT", explanation: "From \\(v = u + at\\) for the first phase." }, { stepNumber: 2, description: "Find the distance in the acceleration phase.", workingLatex: "s_1 = \\tfrac{1}{2}aT^2 = \\tfrac{1}{2}a\\left(\\frac{V}{a}\\right)^2 = \\frac{V^2}{2a}", explanation: "Substituting \\(T = V/a\\)." }, { stepNumber: 3, description: "Find the distance in the deceleration phase using \\(v^2 = u^2 + 2as\\).", workingLatex: "0 = V^2 + 2(-2a)s_2 \\implies s_2 = \\frac{V^2}{4a}", explanation: "Deceleration is \\(2a\\)." }, { stepNumber: 4, description: "Add to find total distance.", workingLatex: "s = s_1 + s_2 = \\frac{V^2}{2a} + \\frac{V^2}{4a} = \\frac{2V^2 + V^2}{4a} = \\frac{3V^2}{4a}", explanation: "As required." }], finalAnswer: "Total distance \\(= \\dfrac{3V^2}{4a}\\) as required." } },
    { id: "y1k1-026", topicRef: "y1k1", topicTitle: "Kinematics 26", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["suvat", "meeting problem", "two objects"], questionText: "Two cars start from the same point on a straight road. Car A starts from rest and accelerates uniformly at \\(2\\) m/s\\(^2\\). Three seconds later, car B passes the same point travelling at a constant speed of \\(12\\) m/s. Find the time after car A starts at which car B overtakes car A.", workedSolution: { steps: [{ stepNumber: 1, description: "Write the displacement of car A at time \\(t\\) seconds after A starts.", workingLatex: "s_A = \\tfrac{1}{2}(2)t^2 = t^2", explanation: "Car A starts from rest with acceleration 2 m/s\\(^2\\)." }, { stepNumber: 2, description: "Write the displacement of car B. Car B starts 3 s later, so it has been travelling for \\((t - 3)\\) seconds when \\(t > 3\\).", workingLatex: "s_B = 12(t - 3)", explanation: "Car B travels at constant speed 12 m/s." }, { stepNumber: 3, description: "Set \\(s_A = s_B\\) for the overtaking point.", workingLatex: "t^2 = 12(t - 3) \\implies t^2 - 12t + 36 = 0", explanation: "" }, { stepNumber: 4, description: "Factorise and solve.", workingLatex: "(t - 6)^2 = 0 \\implies t = 6 \\text{ s}", explanation: "B just catches A at \\(t = 6\\) s. At this moment \\(s_A = 36\\) m and \\(s_B = 12(3) = 36\\) m. Since A's speed at \\(t = 6\\) is \\(2 \\times 6 = 12\\) m/s, equalling B's speed, B catches A at exactly this instant." }], finalAnswer: "Car B overtakes car A at \\(t = 6\\) s, when both have travelled \\(36\\) m." } },
    { id: "y1k1-027", topicRef: "y1k1", topicTitle: "Kinematics 27", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["suvat", "vertical motion", "quadratic", "two times"], questionText: "A ball is projected vertically upward from ground level at \\(24.5\\) m/s. Taking \\(g = 9.8\\) m/s\\(^2\\), find the two times at which the ball is \\(19.6\\) m above the ground.", workedSolution: { steps: [{ stepNumber: 1, description: "Take upward as positive. Use \\(s = ut + \\tfrac{1}{2}at^2\\) with \\(s = 19.6\\).", workingLatex: "19.6 = 24.5t - 4.9t^2", explanation: "" }, { stepNumber: 2, description: "Rearrange to standard form.", workingLatex: "4.9t^2 - 24.5t + 19.6 = 0", explanation: "Divide through by 4.9." }, { stepNumber: 3, description: "Simplify by dividing by 4.9.", workingLatex: "t^2 - 5t + 4 = 0", explanation: "" }, { stepNumber: 4, description: "Factorise and solve.", workingLatex: "(t - 1)(t - 4) = 0 \\implies t = 1 \\text{ or } t = 4", explanation: "The smaller value is on the way up; the larger is on the way down." }], finalAnswer: "The ball is at \\(19.6\\) m at \\(t = 1\\) s (on the way up) and \\(t = 4\\) s (on the way down)." } },
    { id: "y1k1-028", topicRef: "y1k1", topicTitle: "Kinematics 28", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["suvat", "simultaneous equations", "constant acceleration"], questionText: "A particle moves in a straight line with constant acceleration. It passes point \\(A\\) with speed \\(6\\) m/s and point \\(B\\), which is \\(40\\) m from \\(A\\), with speed \\(14\\) m/s. Find (a) the acceleration and (b) the time to travel from \\(A\\) to \\(B\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Use \\(v^2 = u^2 + 2as\\) to find the acceleration.", workingLatex: "14^2 = 6^2 + 2a(40) \\implies 196 = 36 + 80a \\implies 80a = 160 \\implies a = 2 \\text{ m/s}^2", explanation: "" }, { stepNumber: 2, description: "Use \\(v = u + at\\) to find the time.", workingLatex: "14 = 6 + 2t \\implies 2t = 8 \\implies t = 4 \\text{ s}", explanation: "" }], finalAnswer: "(a) \\(a = 2\\) m/s\\(^2\\). (b) \\(t = 4\\) s." } },
    { id: "y1k1-029", topicRef: "y1k1", topicTitle: "Kinematics 29", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["suvat", "show that", "constant acceleration"], questionText: "A car starts from rest and accelerates uniformly, covering \\(20\\) m in the first \\(4\\) s. Show that the car covers \\(60\\) m in the next \\(4\\) s.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the acceleration from the first 4 s.", workingLatex: "s = ut + \\tfrac{1}{2}at^2: \\quad 20 = 0 + \\tfrac{1}{2}a(4)^2 = 8a \\implies a = 2.5 \\text{ m/s}^2", explanation: "" }, { stepNumber: 2, description: "Find the total distance in the first 8 s.", workingLatex: "s_8 = \\tfrac{1}{2}(2.5)(8)^2 = \\tfrac{1}{2}(2.5)(64) = 80 \\text{ m}", explanation: "" }, { stepNumber: 3, description: "Find the distance covered in the next 4 s (from \\(t = 4\\) to \\(t = 8\\)).", workingLatex: "s_{\\text{next}} = s_8 - s_4 = 80 - 20 = 60 \\text{ m}", explanation: "As required." }], finalAnswer: "The car covers \\(60\\) m in the next \\(4\\) s, as required." } },
    { id: "y1k1-030", topicRef: "y1k1", topicTitle: "Kinematics 30", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Standard", tags: ["suvat", "multi-part", "braking", "real-world"], questionText: "A car is travelling along a straight road at \\(30\\) m/s. The driver sees an obstacle and reacts for \\(0.8\\) s before applying the brakes. Under braking, the car decelerates uniformly at \\(6\\) m/s\\(^2\\). Find (a) the thinking distance, (b) the braking distance, (c) the total stopping distance, and (d) the total time from seeing the obstacle to stopping.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the thinking distance (constant speed during reaction time).", workingLatex: "s_1 = 30 \\times 0.8 = 24 \\text{ m}", explanation: "" }, { stepNumber: 2, description: "Find the braking distance using \\(v^2 = u^2 + 2as\\).", workingLatex: "0 = 30^2 + 2(-6)s_2 \\implies 12s_2 = 900 \\implies s_2 = 75 \\text{ m}", explanation: "" }, { stepNumber: 3, description: "Find the total stopping distance.", workingLatex: "s = 24 + 75 = 99 \\text{ m}", explanation: "" }, { stepNumber: 4, description: "Find the braking time.", workingLatex: "0 = 30 - 6t_2 \\implies t_2 = 5 \\text{ s}", explanation: "" }, { stepNumber: 5, description: "Find the total time.", workingLatex: "T = 0.8 + 5 = 5.8 \\text{ s}", explanation: "" }], finalAnswer: "(a) Thinking distance \\(= 24\\) m. (b) Braking distance \\(= 75\\) m. (c) Total stopping distance \\(= 99\\) m. (d) Total time \\(= 5.8\\) s." } },
    { id: "y1k1-031", topicRef: "y1k1", topicTitle: "Kinematics 31", yearCreated: 2026, examStyle: true, marks: 9, difficulty: "Standard", tags: ["suvat", "multi-part", "vertical motion", "ball thrown"], questionText: "A ball is thrown vertically upward from a point \\(1.2\\) m above the ground with speed \\(9.8\\) m/s. Taking \\(g = 9.8\\) m/s\\(^2\\), find (a) the greatest height above the ground reached by the ball, (b) the time taken from throwing to reaching the greatest height, (c) the speed of the ball when it hits the ground, and (d) the total time of flight.", workedSolution: { steps: [{ stepNumber: 1, description: "Take upward as positive with origin at the point of release (1.2 m above ground). Find the height gained above the release point.", workingLatex: "v^2 = u^2 + 2as: \\quad 0 = 9.8^2 + 2(-9.8)s \\implies s = \\frac{96.04}{19.6} = 4.9 \\text{ m}", explanation: "" }, { stepNumber: 2, description: "Find the greatest height above the ground.", workingLatex: "H = 1.2 + 4.9 = 6.1 \\text{ m}", explanation: "" }, { stepNumber: 3, description: "Find the time to the greatest height.", workingLatex: "v = u + at: \\quad 0 = 9.8 - 9.8t \\implies t = 1 \\text{ s}", explanation: "" }, { stepNumber: 4, description: "Find the speed when it hits the ground. The ball falls from the release point to the ground, a displacement of \\(-1.2\\) m.", workingLatex: "v^2 = 9.8^2 + 2(-9.8)(-1.2) = 96.04 + 23.52 = 119.56 \\implies v = \\sqrt{119.56} \\approx 10.93 \\text{ m/s}", explanation: "Using the full journey from the release point." }, { stepNumber: 5, description: "Find the total time of flight. Ground is at \\(s = -1.2\\) from the release point.", workingLatex: "-1.2 = 9.8t - 4.9t^2 \\implies 4.9t^2 - 9.8t - 1.2 = 0", explanation: "" }, { stepNumber: 6, description: "Apply the quadratic formula.", workingLatex: "t = \\frac{9.8 \\pm \\sqrt{96.04 + 23.52}}{9.8} = \\frac{9.8 \\pm \\sqrt{119.56}}{9.8} = \\frac{9.8 \\pm 10.93}{9.8}", explanation: "" }, { stepNumber: 7, description: "Take the positive root.", workingLatex: "t = \\frac{9.8 + 10.93}{9.8} = \\frac{20.73}{9.8} \\approx 2.12 \\text{ s}", explanation: "" }], finalAnswer: "(a) Greatest height \\(= 6.1\\) m. (b) Time to greatest height \\(= 1\\) s. (c) Speed at ground \\(\\approx 10.9\\) m/s. (d) Total time \\(\\approx 2.1\\) s." } },
    { id: "y1k1-032", topicRef: "y1k1", topicTitle: "Kinematics 32", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Standard", tags: ["velocity-time graph", "multi-part", "acceleration", "displacement"], questionText: "A velocity--time graph for a particle is described as follows: from \\(t = 0\\) to \\(t = 5\\) s, velocity increases uniformly from \\(0\\) to \\(10\\) m/s; from \\(t = 5\\) to \\(t = 15\\) s, velocity remains at \\(10\\) m/s; from \\(t = 15\\) to \\(t = 20\\) s, velocity decreases uniformly from \\(10\\) to \\(0\\) m/s. Find (a) the acceleration in the first stage, (b) the deceleration in the last stage, (c) the total displacement, and (d) the average speed for the entire journey.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the acceleration in the first stage.", workingLatex: "a_1 = \\frac{10 - 0}{5 - 0} = 2 \\text{ m/s}^2", explanation: "" }, { stepNumber: 2, description: "Find the deceleration in the last stage.", workingLatex: "a_3 = \\frac{0 - 10}{20 - 15} = -2 \\text{ m/s}^2", explanation: "Deceleration is 2 m/s\\(^2\\)." }, { stepNumber: 3, description: "Find the total displacement using the area under the graph (trapezium).", workingLatex: "s = \\tfrac{1}{2}(10)(5) + (10)(10) + \\tfrac{1}{2}(10)(5) = 25 + 100 + 25 = 150 \\text{ m}", explanation: "Three regions: two triangles and a rectangle." }, { stepNumber: 4, description: "Find the average speed.", workingLatex: "\\text{Average speed} = \\frac{150}{20} = 7.5 \\text{ m/s}", explanation: "" }], finalAnswer: "(a) Acceleration \\(= 2\\) m/s\\(^2\\). (b) Deceleration \\(= 2\\) m/s\\(^2\\). (c) Total displacement \\(= 150\\) m. (d) Average speed \\(= 7.5\\) m/s." } },
    { id: "y1k1-033", topicRef: "y1k1", topicTitle: "Kinematics 33", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["suvat", "two particles", "vertical motion", "algebraic proof", "show that"], questionText: "Two particles are projected vertically upward from the same point \\(O\\). Particle \\(P\\) is projected with speed \\(U\\) m/s at \\(t = 0\\). At \\(t = T\\) seconds, particle \\(Q\\) is projected from \\(O\\) with speed \\(2U\\) m/s. Both move under gravity \\(g\\). (a) Write expressions for the heights of \\(P\\) and \\(Q\\) above \\(O\\) at time \\(t\\) seconds after \\(P\\) is projected, for \\(t > T\\). (b) Show that the two particles are at the same height when \\(t = \\dfrac{T(4U + gT)}{2(U + gT)}\\). (c) State the condition on \\(U\\), \\(g\\) and \\(T\\) for both particles to still be in flight at this instant.", workedSolution: { steps: [{ stepNumber: 1, description: "Write the height of \\(P\\) at time \\(t\\).", workingLatex: "h_P = Ut - \\tfrac{1}{2}gt^2", explanation: "\\(P\\) is projected at \\(t = 0\\) with speed \\(U\\) upward." }, { stepNumber: 2, description: "Write the height of \\(Q\\) at time \\(t\\). Since \\(Q\\) is projected at \\(t = T\\), it has been moving for \\((t - T)\\) seconds.", workingLatex: "h_Q = 2U(t - T) - \\tfrac{1}{2}g(t - T)^2 \\quad \\text{for } t > T", explanation: "\\(Q\\) is projected with speed \\(2U\\) at time \\(t = T\\)." }, { stepNumber: 3, description: "Set \\(h_P = h_Q\\).", workingLatex: "Ut - \\tfrac{1}{2}gt^2 = 2U(t - T) - \\tfrac{1}{2}g(t - T)^2", explanation: "" }, { stepNumber: 4, description: "Expand the right-hand side.", workingLatex: "2Ut - 2UT - \\tfrac{1}{2}g(t^2 - 2tT + T^2) = 2Ut - 2UT - \\tfrac{1}{2}gt^2 + gtT - \\tfrac{1}{2}gT^2", explanation: "" }, { stepNumber: 5, description: "Cancel the \\(-\\tfrac{1}{2}gt^2\\) terms from both sides.", workingLatex: "Ut = 2Ut - 2UT + gtT - \\tfrac{1}{2}gT^2", explanation: "" }, { stepNumber: 6, description: "Rearrange by collecting \\(t\\) terms on the left.", workingLatex: "Ut - 2Ut - gtT = -2UT - \\tfrac{1}{2}gT^2 \\implies -t(U + gT) = -(2UT + \\tfrac{1}{2}gT^2)", explanation: "" }, { stepNumber: 7, description: "Divide both sides by \\(-(U + gT)\\) and simplify.", workingLatex: "t = \\frac{2UT + \\tfrac{1}{2}gT^2}{U + gT} = \\frac{T(2U + \\tfrac{1}{2}gT)}{U + gT} = \\frac{T(4U + gT)}{2(U + gT)} \\quad \\text{as required.}", explanation: "Multiplying numerator and denominator by 2 to clear the fraction." }, { stepNumber: 8, description: "For part (c), \\(P\\) returns to \\(O\\) at \\(t = 2U/g\\) and \\(Q\\) returns at \\(t = T + 4U/g\\). Both must be in flight, so we need \\(t < 2U/g\\).", workingLatex: "\\frac{T(4U + gT)}{2(U + gT)} < \\frac{2U}{g} \\implies gT(4U + gT) < 4U(U + gT) \\implies 4UgT + g^2T^2 < 4U^2 + 4UgT \\implies g^2T^2 < 4U^2 \\implies gT < 2U", explanation: "So the condition is \\(T < 2U/g\\), meaning \\(Q\\) must be projected before \\(P\\) returns to \\(O\\)." }], finalAnswer: "(a) \\(h_P = Ut - \\tfrac{1}{2}gt^2\\), \\(h_Q = 2U(t-T) - \\tfrac{1}{2}g(t-T)^2\\). (b) They meet at \\(t = \\dfrac{T(4U+gT)}{2(U+gT)}\\) as required. (c) Both are in flight provided \\(T < \\dfrac{2U}{g}\\)." } },
    { id: "y1k1-034", topicRef: "y1k1", topicTitle: "Kinematics 34", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["suvat", "nth second", "algebraic proof", "show that", "derivation"], questionText: "A particle moves along a straight line with initial speed \\(u\\) m/s and constant acceleration \\(a\\) m/s\\(^2\\). (a) By considering the displacement from \\(t = 0\\) to \\(t = n\\) and from \\(t = 0\\) to \\(t = n - 1\\), show that the distance covered in the \\(n\\)th second of motion is \\(u + \\tfrac{1}{2}a(2n - 1)\\). (b) A car has initial speed \\(4\\) m/s and constant acceleration \\(3\\) m/s\\(^2\\). Using the result from (a), find the distance covered in the 5th second. (c) Verify your answer to (b) by computing the total distances in the first 5 and first 4 seconds and subtracting.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the displacement from \\(t = 0\\) to \\(t = n\\).", workingLatex: "s_n = un + \\tfrac{1}{2}an^2", explanation: "Using \\(s = ut + \\tfrac{1}{2}at^2\\) with \\(t = n\\)." }, { stepNumber: 2, description: "Find the displacement from \\(t = 0\\) to \\(t = n-1\\).", workingLatex: "s_{n-1} = u(n-1) + \\tfrac{1}{2}a(n-1)^2", explanation: "" }, { stepNumber: 3, description: "Subtract to find the distance in the \\(n\\)th second.", workingLatex: "d_n = s_n - s_{n-1} = un + \\tfrac{1}{2}an^2 - u(n-1) - \\tfrac{1}{2}a(n-1)^2", explanation: "" }, { stepNumber: 4, description: "Simplify.", workingLatex: "d_n = u(n - n + 1) + \\tfrac{1}{2}a\\bigl(n^2 - (n-1)^2\\bigr) = u + \\tfrac{1}{2}a(n^2 - n^2 + 2n - 1) = u + \\tfrac{1}{2}a(2n - 1)", explanation: "Using the difference of squares: \\(n^2 - (n-1)^2 = (2n-1)\\). This completes the proof." }, { stepNumber: 5, description: "Part (b): Substitute \\(u = 4\\), \\(a = 3\\), \\(n = 5\\).", workingLatex: "d_5 = 4 + \\tfrac{1}{2}(3)(2 \\times 5 - 1) = 4 + \\tfrac{1}{2}(3)(9) = 4 + 13.5 = 17.5 \\text{ m}", explanation: "" }, { stepNumber: 6, description: "Part (c): Verify. Total distance in first 5 seconds:", workingLatex: "s_5 = 4(5) + \\tfrac{1}{2}(3)(25) = 20 + 37.5 = 57.5 \\text{ m}", explanation: "" }, { stepNumber: 7, description: "Total distance in first 4 seconds:", workingLatex: "s_4 = 4(4) + \\tfrac{1}{2}(3)(16) = 16 + 24 = 40 \\text{ m}", explanation: "" }, { stepNumber: 8, description: "Subtract to verify.", workingLatex: "s_5 - s_4 = 57.5 - 40 = 17.5 \\text{ m} \\quad \\checkmark", explanation: "This confirms the answer from part (b)." }], finalAnswer: "(a) Distance in the \\(n\\)th second \\(= u + \\tfrac{1}{2}a(2n-1)\\) as required. (b) \\(d_5 = 17.5\\) m. (c) Verified: \\(57.5 - 40 = 17.5\\) m." } },
    { id: "y1k1-035", topicRef: "y1k1", topicTitle: "Kinematics 35", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["average speed", "algebraic proof", "show that", "harmonic mean"], questionText: "A car travels from \\(A\\) to \\(B\\), a distance \\(d\\), at constant speed \\(v_1\\). It immediately returns from \\(B\\) to \\(A\\) at constant speed \\(v_2\\). (a) Find the total time for the round trip in terms of \\(d\\), \\(v_1\\) and \\(v_2\\). (b) Show that the average speed for the whole journey is \\(\\dfrac{2v_1 v_2}{v_1 + v_2}\\). (c) Explain why the average speed is not \\(\\dfrac{v_1 + v_2}{2}\\). (d) Given \\(v_1 = 40\\) km/h and \\(v_2 = 60\\) km/h, find the average speed for the round trip.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the time for each leg.", workingLatex: "t_1 = \\frac{d}{v_1}, \\quad t_2 = \\frac{d}{v_2}", explanation: "Time = distance / speed for each leg." }, { stepNumber: 2, description: "Find the total time for part (a).", workingLatex: "T = t_1 + t_2 = \\frac{d}{v_1} + \\frac{d}{v_2} = \\frac{dv_2 + dv_1}{v_1 v_2} = \\frac{d(v_1 + v_2)}{v_1 v_2}", explanation: "" }, { stepNumber: 3, description: "The total distance for the round trip is \\(2d\\). Compute average speed.", workingLatex: "\\text{Average speed} = \\frac{\\text{total distance}}{\\text{total time}} = \\frac{2d}{\\dfrac{d(v_1 + v_2)}{v_1 v_2}} = \\frac{2d \\cdot v_1 v_2}{d(v_1 + v_2)} = \\frac{2v_1 v_2}{v_1 + v_2}", explanation: "As required for part (b)." }, { stepNumber: 4, description: "Part (c): Explain why the average is not \\((v_1 + v_2)/2\\).", workingLatex: "\\text{The arithmetic mean } \\frac{v_1 + v_2}{2} \\text{ would only apply if equal times were spent at each speed.}", explanation: "Since equal distances (not equal times) are covered at each speed, more time is spent at the slower speed, pulling the average below the arithmetic mean. The correct average is the harmonic mean." }, { stepNumber: 5, description: "Part (d): Substitute \\(v_1 = 40\\), \\(v_2 = 60\\).", workingLatex: "\\text{Average speed} = \\frac{2 \\times 40 \\times 60}{40 + 60} = \\frac{4800}{100} = 48 \\text{ km/h}", explanation: "Note this is less than the arithmetic mean \\((40+60)/2 = 50\\) km/h, confirming the reasoning in part (c)." }], finalAnswer: "(a) \\(T = \\dfrac{d(v_1+v_2)}{v_1 v_2}\\). (b) Average speed \\(= \\dfrac{2v_1 v_2}{v_1+v_2}\\) as required. (c) The arithmetic mean applies only when equal times are spent at each speed; here equal distances are covered, so more time is spent at the slower speed. (d) Average speed \\(= 48\\) km/h." } },
    { id: "y1k1-036", topicRef: "y1k1", topicTitle: "Kinematics 36", yearCreated: 2026, examStyle: true, marks: 10, difficulty: "Challenge", tags: ["suvat", "bouncing ball", "geometric series", "show that", "modelling"], questionText: "A ball is dropped from rest from a height \\(H\\) metres above the ground. Each time it bounces, it rises to a fraction \\(e\\) of the height from which it fell (where \\(0 < e < 1\\)). Assume the bounces are instantaneous and take \\(g\\) as the acceleration due to gravity. (a) Show that the time for the ball to fall from height \\(H\\) is \\(\\sqrt{2H/g}\\). (b) Show that the time between the first and second bounces is \\(2\\sqrt{2eH/g}\\). (c) Show that the total distance the ball travels before coming to rest is \\(H \\cdot \\dfrac{1 + e}{1 - e}\\). (d) Given \\(H = 5\\) m and \\(e = 0.64\\), find the total distance.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Use \\(s = ut + \\tfrac{1}{2}gt^2\\) with \\(u = 0\\), \\(s = H\\) (taking downward as positive).", workingLatex: "H = \\tfrac{1}{2}g t_0^2 \\implies t_0 = \\sqrt{\\frac{2H}{g}} \\quad \\text{as required.}", explanation: "" }, { stepNumber: 2, description: "After the first bounce, the ball rises to height \\(eH\\). The time to rise from the ground to height \\(eH\\) equals the time to fall from \\(eH\\) to the ground.", workingLatex: "t_{\\text{fall from } eH} = \\sqrt{\\frac{2eH}{g}}", explanation: "" }, { stepNumber: 3, description: "Part (b): The time between the 1st and 2nd bounces includes the rise and the fall, which are equal.", workingLatex: "t_1 = 2\\sqrt{\\frac{2eH}{g}} \\quad \\text{as required.}", explanation: "The ball rises to \\(eH\\) and falls back, each taking \\(\\sqrt{2eH/g}\\)." }, { stepNumber: 4, description: "Part (c): The total distance is the initial fall \\(H\\), plus up-and-down distances for each subsequent bounce.", workingLatex: "D = H + 2eH + 2e^2H + 2e^3H + \\cdots = H + 2H(e + e^2 + e^3 + \\cdots)", explanation: "After each bounce the ball rises and falls the same distance, giving a factor of 2. The heights form a geometric sequence: \\(eH, e^2H, e^3H, \\ldots\\)" }, { stepNumber: 5, description: "Sum the geometric series \\(e + e^2 + e^3 + \\cdots = e/(1-e)\\).", workingLatex: "D = H + 2H \\cdot \\frac{e}{1 - e} = H\\left(1 + \\frac{2e}{1-e}\\right) = H \\cdot \\frac{1 - e + 2e}{1 - e} = H \\cdot \\frac{1 + e}{1 - e}", explanation: "As required." }, { stepNumber: 6, description: "Part (d): Substitute \\(H = 5\\) and \\(e = 0.64\\).", workingLatex: "D = 5 \\times \\frac{1 + 0.64}{1 - 0.64} = 5 \\times \\frac{1.64}{0.36} = 5 \\times \\frac{41}{9} \\approx 22.8 \\text{ m}", explanation: "" }], finalAnswer: "(a) \\(t_0 = \\sqrt{2H/g}\\) as required. (b) Time between 1st and 2nd bounces \\(= 2\\sqrt{2eH/g}\\) as required. (c) Total distance \\(= \\dfrac{H(1+e)}{1-e}\\) as required. (d) \\(D \\approx 22.8\\) m." } },
    { id: "y1k1-037", topicRef: "y1k1", topicTitle: "Kinematics 37", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["suvat", "two particles", "vertical motion", "algebraic", "simultaneous"], questionText: "A particle \\(P\\) is projected vertically upward from a point \\(O\\) on the ground with speed \\(u\\) m/s. At the instant when \\(P\\) has been moving for \\(T\\) seconds (where \\(T < u/g\\)), a second particle \\(Q\\) is projected vertically upward from \\(O\\) with speed \\(2u\\) m/s. (a) Show that, at time \\(t\\) seconds after \\(Q\\) is projected, the height of \\(P\\) above \\(O\\) is \\(u(t + T) - \\tfrac{1}{2}g(t + T)^2\\). (b) Find the height of \\(Q\\) above \\(O\\) at this time. (c) Show that the two particles are at the same height when \\(t = \\dfrac{uT - \\tfrac{1}{2}gT^2}{u + gT}\\). (d) Given \\(u = 25\\), \\(g = 10\\) and \\(T = 1\\), find \\(t\\) and the height at which they meet.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): \\(P\\) was projected at time \\(T\\) seconds before \\(Q\\). At time \\(t\\) after \\(Q\\) is projected, \\(P\\) has been moving for \\((t + T)\\) seconds.", workingLatex: "h_P = u(t + T) - \\tfrac{1}{2}g(t + T)^2 \\quad \\text{as required.}", explanation: "" }, { stepNumber: 2, description: "Part (b): \\(Q\\) has been moving for \\(t\\) seconds.", workingLatex: "h_Q = 2ut - \\tfrac{1}{2}gt^2", explanation: "" }, { stepNumber: 3, description: "Part (c): Set \\(h_P = h_Q\\).", workingLatex: "u(t + T) - \\tfrac{1}{2}g(t + T)^2 = 2ut - \\tfrac{1}{2}gt^2", explanation: "" }, { stepNumber: 4, description: "Expand the left-hand side.", workingLatex: "ut + uT - \\tfrac{1}{2}g(t^2 + 2tT + T^2) = ut + uT - \\tfrac{1}{2}gt^2 - gtT - \\tfrac{1}{2}gT^2", explanation: "" }, { stepNumber: 5, description: "Equate with the right-hand side and cancel \\(-\\tfrac{1}{2}gt^2\\).", workingLatex: "ut + uT - gtT - \\tfrac{1}{2}gT^2 = 2ut", explanation: "" }, { stepNumber: 6, description: "Rearrange to isolate \\(t\\).", workingLatex: "uT - gtT - \\tfrac{1}{2}gT^2 = 2ut - ut = ut \\implies ut + gtT = uT - \\tfrac{1}{2}gT^2", explanation: "" }, { stepNumber: 7, description: "Factor out \\(t\\) on the left.", workingLatex: "t(u + gT) = uT - \\tfrac{1}{2}gT^2 \\implies t = \\frac{uT - \\tfrac{1}{2}gT^2}{u + gT} \\quad \\text{as required.}", explanation: "" }, { stepNumber: 8, description: "Part (d): Substitute \\(u = 25\\), \\(g = 10\\), \\(T = 1\\).", workingLatex: "t = \\frac{25(1) - \\tfrac{1}{2}(10)(1)}{25 + 10(1)} = \\frac{25 - 5}{35} = \\frac{20}{35} = \\frac{4}{7} \\text{ s}", explanation: "" }, { stepNumber: 9, description: "Find the height using \\(h_Q\\).", workingLatex: "h = 2(25)\\left(\\frac{4}{7}\\right) - \\tfrac{1}{2}(10)\\left(\\frac{4}{7}\\right)^2 = \\frac{200}{7} - 5 \\times \\frac{16}{49} = \\frac{200}{7} - \\frac{80}{49} = \\frac{1400 - 80}{49} = \\frac{1320}{49} \\approx 26.9 \\text{ m}", explanation: "" }], finalAnswer: "(a) \\(h_P = u(t+T) - \\tfrac{1}{2}g(t+T)^2\\) as required. (b) \\(h_Q = 2ut - \\tfrac{1}{2}gt^2\\). (c) \\(t = \\dfrac{uT - \\tfrac{1}{2}gT^2}{u + gT}\\) as required. (d) \\(t = \\tfrac{4}{7}\\) s, height \\(\\approx 26.9\\) m." } },
    { id: "y1k1-038", topicRef: "y1k1", topicTitle: "Kinematics 38", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["suvat", "sign convention", "return to origin", "algebraic proof", "show that"], questionText: "A particle moves along a straight line. At \\(t = 0\\) it is at the origin \\(O\\) with velocity \\(u\\) m/s. It has constant acceleration \\(a\\) m/s\\(^2\\), where \\(a\\) and \\(u\\) have opposite signs. (a) Explain why the particle will initially move away from \\(O\\) and then return. (b) Show that the particle returns to \\(O\\) at time \\(t = -\\dfrac{2u}{a}\\), and verify that this is positive. (c) Find the velocity of the particle when it returns to \\(O\\), in terms of \\(u\\). (d) Find the maximum distance from \\(O\\) reached by the particle, in terms of \\(u\\) and \\(a\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Since \\(u\\) and \\(a\\) have opposite signs, the particle initially moves in the direction of \\(u\\) but decelerates.", workingLatex: "\\text{The acceleration opposes the initial velocity, so the particle slows, stops, reverses, and returns to } O.", explanation: "The acceleration is directed toward the origin (since it opposes the initial motion), so the particle will slow down, momentarily stop, then accelerate back through \\(O\\)." }, { stepNumber: 2, description: "Part (b): The particle is at \\(O\\) when \\(s = 0\\). Use \\(s = ut + \\tfrac{1}{2}at^2\\).", workingLatex: "0 = ut + \\tfrac{1}{2}at^2 = t\\left(u + \\tfrac{1}{2}at\\right)", explanation: "" }, { stepNumber: 3, description: "Solve for \\(t\\).", workingLatex: "t = 0 \\quad \\text{or} \\quad u + \\tfrac{1}{2}at = 0 \\implies t = -\\frac{2u}{a}", explanation: "\\(t = 0\\) is the initial position; the other solution is the return time." }, { stepNumber: 4, description: "Verify this is positive. Since \\(u\\) and \\(a\\) have opposite signs, \\(-u/a > 0\\), so \\(-2u/a > 0\\).", workingLatex: "\\text{If } u > 0 \\text{ then } a < 0, \\text{ so } -2u/a = 2u/|a| > 0. \\text{ Similarly if } u < 0 \\text{ then } a > 0, \\text{ giving } -2u/a = 2|u|/a > 0.", explanation: "As required." }, { stepNumber: 5, description: "Part (c): Find the velocity at \\(t = -2u/a\\) using \\(v = u + at\\).", workingLatex: "v = u + a\\left(-\\frac{2u}{a}\\right) = u - 2u = -u", explanation: "The particle returns to the origin with speed \\(|u|\\), but in the opposite direction to its initial velocity." }, { stepNumber: 6, description: "Part (d): The particle is furthest from \\(O\\) when \\(v = 0\\). Find this time.", workingLatex: "0 = u + at^* \\implies t^* = -\\frac{u}{a}", explanation: "This is half the return time, which makes sense by symmetry." }, { stepNumber: 7, description: "Find the maximum distance.", workingLatex: "s_{\\max} = u\\left(-\\frac{u}{a}\\right) + \\tfrac{1}{2}a\\left(-\\frac{u}{a}\\right)^2 = -\\frac{u^2}{a} + \\frac{u^2}{2a} = -\\frac{u^2}{2a}", explanation: "Since \\(a\\) and \\(u\\) have opposite signs, \\(-u^2/(2a) > 0\\), confirming positive distance." }], finalAnswer: "(a) The acceleration opposes the velocity, so the particle decelerates, stops, reverses and returns. (b) Returns at \\(t = -2u/a > 0\\) as required. (c) Velocity on return \\(= -u\\) (same speed, opposite direction). (d) Maximum distance from \\(O\\) is \\(-u^2/(2a) = u^2/(2|a|)\\)." } },
    { id: "y1k1-039", topicRef: "y1k1", topicTitle: "Kinematics 39", yearCreated: 2026, examStyle: true, marks: 9, difficulty: "Challenge", tags: ["suvat", "two particles", "meeting problem", "quadratic", "modelling"], questionText: "Particles \\(A\\) and \\(B\\) move along a straight road. At \\(t = 0\\), particle \\(A\\) passes a point \\(O\\) travelling in the positive direction with speed \\(5\\) m/s and constant acceleration \\(2\\) m/s\\(^2\\). At the same instant, particle \\(B\\) is \\(50\\) m ahead of \\(O\\) (in the positive direction), travelling toward \\(O\\) with speed \\(10\\) m/s and decelerating at \\(1\\) m/s\\(^2\\) (so its acceleration is \\(+1\\) m/s\\(^2\\) since it opposes the motion toward \\(O\\)). (a) Write expressions for the positions of \\(A\\) and \\(B\\) relative to \\(O\\) at time \\(t\\). (b) Find the time(s) at which they meet. (c) Find the position(s) at which they meet. (d) Explain what happens physically at each meeting.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Position of \\(A\\). Takes positive direction from \\(O\\).", workingLatex: "x_A = 5t + \\tfrac{1}{2}(2)t^2 = 5t + t^2", explanation: "\\(A\\) starts at \\(O\\) with speed 5 m/s and acceleration 2 m/s\\(^2\\)." }, { stepNumber: 2, description: "Position of \\(B\\). \\(B\\) starts at \\(x = 50\\), moving in the negative direction at 10 m/s, with acceleration \\(+1\\) m/s\\(^2\\) (decelerating).", workingLatex: "x_B = 50 - 10t + \\tfrac{1}{2}(1)t^2 = 50 - 10t + \\tfrac{1}{2}t^2", explanation: "\\(B\\) moves toward \\(O\\) (negative direction) but decelerates, so the acceleration is positive." }, { stepNumber: 3, description: "Part (b): Set \\(x_A = x_B\\).", workingLatex: "5t + t^2 = 50 - 10t + \\tfrac{1}{2}t^2", explanation: "" }, { stepNumber: 4, description: "Rearrange.", workingLatex: "t^2 - \\tfrac{1}{2}t^2 + 5t + 10t - 50 = 0 \\implies \\tfrac{1}{2}t^2 + 15t - 50 = 0", explanation: "" }, { stepNumber: 5, description: "Multiply through by 2.", workingLatex: "t^2 + 30t - 100 = 0", explanation: "" }, { stepNumber: 6, description: "Apply the quadratic formula.", workingLatex: "t = \\frac{-30 \\pm \\sqrt{900 + 400}}{2} = \\frac{-30 \\pm \\sqrt{1300}}{2}", explanation: "" }, { stepNumber: 7, description: "Evaluate.", workingLatex: "\\sqrt{1300} = 10\\sqrt{13} \\approx 36.06, \\quad t = \\frac{-30 + 36.06}{2} \\approx 3.03 \\text{ s}", explanation: "The other root \\(t = \\frac{-30 - 36.06}{2} \\approx -33\\) is negative and rejected." }, { stepNumber: 8, description: "Part (c): Find the position at \\(t \\approx 3.03\\).", workingLatex: "x_A = 5(3.03) + (3.03)^2 = 15.15 + 9.18 \\approx 24.3 \\text{ m from } O", explanation: "Check with \\(x_B\\): \\(50 - 10(3.03) + \\tfrac{1}{2}(3.03)^2 = 50 - 30.3 + 4.59 \\approx 24.3\\) m. Consistent." }, { stepNumber: 9, description: "Part (d): Physical interpretation.", workingLatex: "\\text{At } t \\approx 3.03 \\text{ s, } A \\text{ (accelerating forward) catches } B \\text{ (which was heading back toward } O \\text{ but decelerating).}", explanation: "\\(B\\) stops at \\(t = 10\\) s (when \\(v_B = -10 + 1 \\times 10 = 0\\)) and then reverses. By that time \\(A\\) has long passed \\(B\\). There is only one meeting because the quadratic has only one positive root." }], finalAnswer: "(a) \\(x_A = 5t + t^2\\), \\(x_B = 50 - 10t + \\tfrac{1}{2}t^2\\). (b) They meet at \\(t = \\dfrac{-30 + 10\\sqrt{13}}{2} \\approx 3.0\\) s. (c) They meet approximately \\(24.3\\) m from \\(O\\). (d) \\(A\\) accelerates forward and catches \\(B\\) as \\(B\\) decelerates while heading back toward \\(O\\); there is only one meeting." } },
    { id: "y1k1-040", topicRef: "y1k1", topicTitle: "Kinematics 40", yearCreated: 2026, examStyle: true, marks: 10, difficulty: "Challenge", tags: ["suvat", "algebraic proof", "show that", "consecutive intervals", "multi-part"], questionText: "A particle moves along a straight line with constant acceleration \\(a\\) m/s\\(^2\\). In two consecutive time intervals, each of length \\(T\\) seconds, it covers distances \\(d_1\\) and \\(d_2\\) respectively. Let \\(u\\) be the speed at the start of the first interval. (a) Show that \\(d_1 = uT + \\tfrac{1}{2}aT^2\\). (b) By finding the speed at the start of the second interval, show that \\(d_2 = uT + \\tfrac{3}{2}aT^2\\). (c) Hence show that \\(a = \\dfrac{d_2 - d_1}{T^2}\\). (d) Find \\(u\\) in terms of \\(d_1\\), \\(d_2\\) and \\(T\\). (e) Given \\(d_1 = 20\\), \\(d_2 = 32\\), and \\(T = 4\\), find \\(a\\) and \\(u\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Apply \\(s = ut + \\tfrac{1}{2}at^2\\) over the first interval of length \\(T\\).", workingLatex: "d_1 = uT + \\tfrac{1}{2}aT^2 \\quad \\text{as required.}", explanation: "" }, { stepNumber: 2, description: "Part (b): Find the speed at the start of the second interval using \\(v = u + aT\\).", workingLatex: "v_1 = u + aT", explanation: "This is the speed at the end of the first interval." }, { stepNumber: 3, description: "Apply \\(s = v_1 T + \\tfrac{1}{2}aT^2\\) for the second interval.", workingLatex: "d_2 = (u + aT)T + \\tfrac{1}{2}aT^2 = uT + aT^2 + \\tfrac{1}{2}aT^2 = uT + \\tfrac{3}{2}aT^2 \\quad \\text{as required.}", explanation: "" }, { stepNumber: 4, description: "Part (c): Subtract the expression for \\(d_1\\) from that for \\(d_2\\).", workingLatex: "d_2 - d_1 = \\left(uT + \\tfrac{3}{2}aT^2\\right) - \\left(uT + \\tfrac{1}{2}aT^2\\right) = aT^2", explanation: "" }, { stepNumber: 5, description: "Solve for \\(a\\).", workingLatex: "a = \\frac{d_2 - d_1}{T^2} \\quad \\text{as required.}", explanation: "" }, { stepNumber: 6, description: "Part (d): Substitute \\(a = (d_2 - d_1)/T^2\\) into the expression for \\(d_1\\).", workingLatex: "d_1 = uT + \\tfrac{1}{2} \\cdot \\frac{d_2 - d_1}{T^2} \\cdot T^2 = uT + \\frac{d_2 - d_1}{2}", explanation: "" }, { stepNumber: 7, description: "Solve for \\(u\\).", workingLatex: "uT = d_1 - \\frac{d_2 - d_1}{2} = \\frac{2d_1 - d_2 + d_1}{2} = \\frac{3d_1 - d_2}{2} \\implies u = \\frac{3d_1 - d_2}{2T}", explanation: "" }, { stepNumber: 8, description: "Part (e): Substitute \\(d_1 = 20\\), \\(d_2 = 32\\), \\(T = 4\\).", workingLatex: "a = \\frac{32 - 20}{16} = \\frac{12}{16} = 0.75 \\text{ m/s}^2", explanation: "" }, { stepNumber: 9, description: "Find \\(u\\).", workingLatex: "u = \\frac{3(20) - 32}{2(4)} = \\frac{60 - 32}{8} = \\frac{28}{8} = 3.5 \\text{ m/s}", explanation: "" }, { stepNumber: 10, description: "Verify: \\(d_1 = 3.5(4) + \\tfrac{1}{2}(0.75)(16) = 14 + 6 = 20\\). \\(d_2 = 3.5(4) + \\tfrac{3}{2}(0.75)(16) = 14 + 18 = 32\\).", workingLatex: "d_1 = 20 \\; \\checkmark, \\quad d_2 = 32 \\; \\checkmark", explanation: "Both check out." }], finalAnswer: "(a) \\(d_1 = uT + \\tfrac{1}{2}aT^2\\) as required. (b) \\(d_2 = uT + \\tfrac{3}{2}aT^2\\) as required. (c) \\(a = (d_2 - d_1)/T^2\\) as required. (d) \\(u = (3d_1 - d_2)/(2T)\\). (e) \\(a = 0.75\\) m/s\\(^2\\), \\(u = 3.5\\) m/s." } },
];
